package claude

import (
	"os"
	"path/filepath"
	"strconv"
	"strings"
	"time"

	"github.com/black-atom-industries/helm/internal/config"
)

// StaleThreshold is how long before a "working" status is considered stale.
// If Claude Code hasn't updated the status file in this time, assume it's not running.
const StaleThreshold = 2 * time.Minute

// WaitingStaleThreshold is how long before a "waiting" status is considered stale.
// Safety net — the TUI handles visual progression (? → ! → Z) before this kicks in.
const WaitingStaleThreshold = 30 * time.Minute

// Status represents Claude Code status for a session
type Status struct {
	State     string    // "new", "working", "waiting", or ""
	Timestamp time.Time // When the status was last updated
}

// IsStale returns true if the status hasn't been updated within the appropriate threshold.
func (s Status) IsStale() bool {
	if s.State == "" {
		return false // No status to be stale
	}
	if s.State == "waiting" {
		return time.Since(s.Timestamp) > WaitingStaleThreshold
	}
	return time.Since(s.Timestamp) > StaleThreshold
}

// GetStatus reads the Claude Code status for a session from the given cache directory.
// Returns empty Status if no status file exists or if status is stale.
func GetStatus(sessionName string, cacheDir string) Status {
	statusFile := filepath.Join(cacheDir, sessionName+config.StatusFileExt)
	content, err := os.ReadFile(statusFile)
	if err != nil {
		return Status{}
	}

	// Parse format: "state:timestamp"
	parts := strings.SplitN(strings.TrimSpace(string(content)), ":", 2)
	if len(parts) != 2 {
		return Status{}
	}

	timestamp, err := strconv.ParseInt(parts[1], 10, 64)
	if err != nil {
		return Status{}
	}

	status := Status{
		State:     parts[0],
		Timestamp: time.Unix(timestamp, 0),
	}

	// If status is stale, treat it as no status
	if status.IsStale() {
		return Status{}
	}

	return status
}

// CleanupStale removes status files for sessions that no longer exist
func CleanupStale(cacheDir string, activeSessions []string) {
	entries, err := os.ReadDir(cacheDir)
	if err != nil {
		return
	}

	activeSet := make(map[string]bool)
	for _, s := range activeSessions {
		activeSet[s] = true
	}

	for _, entry := range entries {
		if !strings.HasSuffix(entry.Name(), config.StatusFileExt) {
			continue
		}

		sessionName := strings.TrimSuffix(entry.Name(), config.StatusFileExt)
		if !activeSet[sessionName] {
			_ = os.Remove(filepath.Join(cacheDir, entry.Name()))
		}
	}
}

package ui

import (
	"fmt"
	"strings"
	"time"

	"github.com/charmbracelet/lipgloss"

	"github.com/black-atom-industries/helm/internal/claude"
	"github.com/black-atom-industries/helm/internal/git"
)

// RowLayout holds calculated column widths for consistent alignment across rows
type RowLayout struct {
	NameWidth      int
	GitStatusWidth int
}

// RowOpts contains options for rendering a generic row
// Required: Num, Name, Selected
// Optional: all others (use zero values to omit)
type RowOpts struct {
	// Required
	Num      int
	Name     string
	Selected bool

	// Optional - set to enable
	ShowExpandIcon   bool           // Show ▸/▾ expand indicator
	Expanded         bool           // Expansion state
	LastActivity     *time.Time     // Show time ago if set
	GitStatus        *git.Status    // Show git status if set
	GitStatusLoading bool           // Show loading indicator for git status
	ClaudeStatus     *claude.Status // Show claude status if set
	AnimFrame        int            // Animation frame for claude status
	IsSelf           bool           // True for the pinned current/self session
}

// WindowRowOpts contains per-row options for rendering a window
type WindowRowOpts struct {
	Selected bool
	Expanded bool // Window is expanded to show panes
}

// PaneRowOpts contains per-row options for rendering a pane
type PaneRowOpts struct {
	Selected bool
}

// Column component functions - each returns a styled string

// SpacerStyle returns a spacer with background when selected
func SpacerStyle(text string, selected bool) string {
	if selected {
		return lipgloss.NewStyle().Background(Colors.Bg.Selected).Render(text)
	}
	return text
}

// RenderIndex renders the session number (1-9)
func RenderIndex(num int, selected bool) string {
	label := fmt.Sprintf("%d", num)
	if selected {
		return IndexSelectedStyle.Render(label)
	}
	return IndexStyle.Render(label)
}

// RenderExpandIcon renders the expand/collapse indicator
func RenderExpandIcon(expanded, selected bool) string {
	if expanded {
		if selected {
			return ExpandedIconSelected
		}
		return ExpandedIcon
	}
	if selected {
		return CollapsedIconSelected
	}
	return CollapsedIcon
}

// RenderName renders a name with padding to a fixed width
func RenderName(name string, width int, selected bool, selectedStyle, defaultStyle lipgloss.Style) string {
	padded := fmt.Sprintf("%-*s", width, name)
	if selected {
		return selectedStyle.Render(padded)
	}
	return defaultStyle.Render(padded)
}

// RenderSessionName renders the session name
func RenderSessionName(name string, width int, selected bool) string {
	return RenderName(name, width, selected, SessionNameSelectedStyle, SessionNameStyle)
}

// RenderWindowName renders the window name with index
func RenderWindowName(index int, name string, selected bool) string {
	text := fmt.Sprintf("%d: %s", index, name)
	if selected {
		return WindowNameSelectedStyle.Render(text)
	}
	return WindowNameStyle.Render(text)
}

// RenderTimeAgo renders the time since last activity
func RenderTimeAgo(t time.Time, selected bool) string {
	timeAgo := FormatTimeAgo(t)
	padded := fmt.Sprintf("%-8s", timeAgo)
	if selected {
		return TimeSelectedStyle.Render(padded)
	}
	return TimeStyle.Render(padded)
}

// FormatTimeAgo formats a time as a human-readable "X ago" string
func FormatTimeAgo(t time.Time) string {
	d := time.Since(t)

	if d < time.Minute {
		return fmt.Sprintf("%ds ago", int(d.Seconds()))
	}
	if d < time.Hour {
		return fmt.Sprintf("%dm ago", int(d.Minutes()))
	}
	if d < 24*time.Hour {
		return fmt.Sprintf("%dh ago", int(d.Hours()))
	}
	return fmt.Sprintf("%dd ago", int(d.Hours()/24))
}

// RenderGitStatusColumn renders the git status with padding to a fixed width
func RenderGitStatusColumn(status *git.Status, maxWidth int, selected bool, loading bool, animFrame int) string {
	if maxWidth == 0 {
		return ""
	}

	// Show spinner if still fetching
	if loading {
		frame := animFrame % len(ClaudeSpinnerFrames)
		spinner := GitLoadingStyle.Render(ClaudeSpinnerFrames[frame])
		if maxWidth > 1 {
			padding := SpacerStyle(strings.Repeat(" ", maxWidth-1), selected)
			return spinner + padding
		}
		return spinner
	}

	if status == nil {
		return SpacerStyle(strings.Repeat(" ", maxWidth), selected)
	}

	formatted := FormatGitStatus(status.Dirty, status.Additions, status.Deletions, selected)
	actualWidth := GitStatusWidth(status.Dirty, status.Additions, status.Deletions)

	if actualWidth < maxWidth {
		padding := SpacerStyle(strings.Repeat(" ", maxWidth-actualWidth), selected)
		return formatted + padding
	}
	return formatted
}

// RenderClaudeIcon renders a single-character Claude status icon
// Returns a space for no status to preserve column alignment
func RenderClaudeIcon(status *claude.Status, animFrame int, selected bool) string {
	if status == nil || status.State == "" {
		return SpacerStyle(" ", selected) // Reserved space for alignment
	}
	waitDuration := time.Since(status.Timestamp)
	icon := FormatClaudeIcon(status.State, animFrame, waitDuration)
	if selected {
		// Re-apply the icon style with background
		return lipgloss.NewStyle().Background(Colors.Bg.Selected).Render(icon)
	}
	return icon
}

// SessionRowOpts wraps RowOpts with session-specific settings
type SessionRowOpts struct {
	RowOpts
}

// RenderSelfIndex renders the self-session marker instead of a number
func RenderSelfIndex(selected bool) string {
	if selected {
		return SelfIndexSelectedStyle.Render("*")
	}
	return SelfIndexStyle.Render("*")
}

// RenderSelfSessionName renders the self-session name
func RenderSelfSessionName(name string, width int, selected bool) string {
	padded := fmt.Sprintf("%-*s", width, name)
	if selected {
		return SelfNameSelectedStyle.Render(padded)
	}
	return SelfNameStyle.Render(padded)
}

// RenderSessionRow composes all columns into a complete session row
func RenderSessionRow(name string, lastActivity time.Time, layout RowLayout, opts SessionRowOpts, width int) string {
	// Self session uses distinct index marker and name style
	renderIndex := RenderIndex(opts.Num, opts.Selected)
	renderName := RenderSessionName(name, layout.NameWidth, opts.Selected)
	if opts.IsSelf {
		renderIndex = RenderSelfIndex(opts.Selected)
		renderName = RenderSelfSessionName(name, layout.NameWidth, opts.Selected)
	}

	cols := []string{
		renderIndex,
		SpacerStyle(" ", opts.Selected),
		// Claude icon (after index, before expand arrow)
		RenderClaudeIcon(opts.ClaudeStatus, opts.AnimFrame, opts.Selected),
		SpacerStyle(" ", opts.Selected),
	}

	// Expand icon (optional)
	if opts.ShowExpandIcon {
		cols = append(cols, RenderExpandIcon(opts.Expanded, opts.Selected), SpacerStyle(" ", opts.Selected))
	}

	// Name (always shown)
	cols = append(cols, renderName)

	// Time ago (optional)
	if opts.LastActivity != nil {
		cols = append(cols, SpacerStyle("  ", opts.Selected), RenderTimeAgo(*opts.LastActivity, opts.Selected))
	}

	// Git status (optional column)
	if layout.GitStatusWidth > 0 {
		cols = append(cols, SpacerStyle(" ", opts.Selected), RenderGitStatusColumn(opts.GitStatus, layout.GitStatusWidth, opts.Selected, opts.GitStatusLoading, opts.AnimFrame))
	}

	content := strings.Join(cols, "")
	if opts.Selected {
		return SessionSelectedStyle.Width(width).Render(content)
	}
	return SessionStyle.Width(width).Render(content)
}

// RenderBookmarkRow composes a bookmark row (simpler than session row)
func RenderBookmarkRow(name string, layout RowLayout, opts RowOpts, width int) string {
	cols := []string{
		RenderIndex(opts.Num, opts.Selected),
		SpacerStyle(" ", opts.Selected),
		// Claude icon column (always reserved for alignment with session rows)
		RenderClaudeIcon(opts.ClaudeStatus, opts.AnimFrame, opts.Selected),
		SpacerStyle(" ", opts.Selected),
		RenderSessionName(name, layout.NameWidth, opts.Selected),
	}

	// Git status (optional)
	if layout.GitStatusWidth > 0 {
		cols = append(cols, SpacerStyle(" ", opts.Selected), RenderGitStatusColumn(opts.GitStatus, layout.GitStatusWidth, opts.Selected, opts.GitStatusLoading, opts.AnimFrame))
	}

	content := strings.Join(cols, "")
	if opts.Selected {
		return SessionSelectedStyle.Width(width).Render(content)
	}
	return SessionStyle.Width(width).Render(content)
}

// TableHeaderOpts controls which columns appear in the header
type TableHeaderOpts struct {
	ShowExpandIcon bool
	ShowTime       bool
	ShowGit        bool
	NameLabel      string // e.g., "Session" or "Bookmark"
}

// RenderTableHeader renders a header row above the content list
func RenderTableHeader(layout RowLayout, opts TableHeaderOpts) string {
	dim := TableHeaderTextStyle // shorthand for dim text

	cols := []string{
		"  ", // Align with scrollbar column in data rows
		dim.Render(fmt.Sprintf("%-3s", "#")),
		" ",
		CCHeaderStyle.Render("CC"), // Claude Code status column (orange)
		" ",
	}

	// Expand icon placeholder
	if opts.ShowExpandIcon {
		cols = append(cols, " ", " ")
	}

	// Name column header
	nameLabel := opts.NameLabel
	if nameLabel == "" {
		nameLabel = "NAME"
	}
	cols = append(cols, dim.Render(fmt.Sprintf("%-*s", layout.NameWidth, nameLabel)))

	// Time column header
	if opts.ShowTime {
		cols = append(cols, "  ", dim.Render(fmt.Sprintf("%-8s", "ACT")))
	}

	// Git column header
	if opts.ShowGit && layout.GitStatusWidth > 0 {
		cols = append(cols, " ", dim.Render(fmt.Sprintf("%-*s", layout.GitStatusWidth, "GIT")))
	}

	content := strings.Join(cols, "")
	return TableHeaderStyle.Render(content)
}

// RenderWindowRow composes a window row
func RenderWindowRow(index int, name string, opts WindowRowOpts, width int) string {
	var parts []string

	// Expand icon for windows (shows if window can be expanded to show panes)
	parts = append(parts, RenderExpandIcon(opts.Expanded, opts.Selected))
	parts = append(parts, SpacerStyle(" ", opts.Selected))

	// Window name with index
	parts = append(parts, RenderWindowName(index, name, opts.Selected))

	content := strings.Join(parts, "")
	if opts.Selected {
		return WindowSelectedStyle.Width(width).Render(content)
	}
	return WindowStyle.Width(width).Render(content)
}

// RenderPaneRow composes a pane row
// Panes are indented further than windows
func RenderPaneRow(index int, command string, active bool, opts PaneRowOpts, width int) string {
	// Format: "index: command" with "*" for active pane
	activeMarker := " "
	if active {
		activeMarker = "*"
	}
	text := fmt.Sprintf("%s %d: %s", activeMarker, index, command)

	if opts.Selected {
		return PaneSelectedStyle.Width(width).Render(text)
	}
	return PaneStyle.Width(width).Render(text)
}

// ItemDepth represents the hierarchy level of an item
// This design allows easy extension for panes (helm-xdn)
type ItemDepth int

const (
	DepthSession ItemDepth = 0
	DepthWindow  ItemDepth = 1
	DepthPane    ItemDepth = 2 // Future use
)

// IndentForDepth returns the left padding for a given depth level
func IndentForDepth(depth ItemDepth) int {
	switch depth {
	case DepthSession:
		return 0
	case DepthWindow:
		return 10 // Matches current WindowStyle.PaddingLeft
	case DepthPane:
		return 14 // Further indented for panes
	default:
		return 0
	}
}

package ui

import (
	"fmt"
	"strings"
	"time"

	"github.com/charmbracelet/lipgloss"
)

// Border and padding overhead for the app container
const (
	// AppBorderOverhead is the total cells used by border + padding per axis
	AppBorderOverheadX = 4 // left border + left padding + right padding + right border
	AppBorderOverheadY = 2 // top border + bottom border (no vertical padding)

	// ScrollbarColumnWidth is the space used by scrollbar + separator
	ScrollbarColumnWidth = 2 // scrollbar char + space
)

// Styles — initialized with dark defaults, call InitColors() to reinitialize for light mode
var (
	// Container styles
	AppStyle          lipgloss.Style
	HeaderStyle       lipgloss.Style
	FooterStyle       lipgloss.Style
	MessageStyle      lipgloss.Style
	ErrorMessageStyle lipgloss.Style

	// Session row styles
	SessionStyle         lipgloss.Style
	SessionSelectedStyle lipgloss.Style

	// Window row styles (indented)
	WindowStyle         lipgloss.Style
	WindowSelectedStyle lipgloss.Style

	// Pane row styles (further indented)
	PaneStyle         lipgloss.Style
	PaneSelectedStyle lipgloss.Style

	// Text styles
	IndexStyle               lipgloss.Style
	IndexSelectedStyle       lipgloss.Style
	SessionNameStyle         lipgloss.Style
	SessionNameSelectedStyle lipgloss.Style
	WindowNameStyle          lipgloss.Style
	WindowNameSelectedStyle  lipgloss.Style

	// Pre-rendered icon strings
	ExpandedIcon          string
	ExpandedIconSelected  string
	CollapsedIcon         string
	CollapsedIconSelected string

	// Time styles
	TimeStyle         lipgloss.Style
	TimeSelectedStyle lipgloss.Style

	// Claude status styles
	ClaudeNewStyle           lipgloss.Style
	ClaudeWorkingStyle       lipgloss.Style
	ClaudeWaitingStyle       lipgloss.Style
	ClaudeWaitingUrgentStyle lipgloss.Style
	ClaudeIdleStyle          lipgloss.Style

	// Git status styles
	GitFilesStyle   lipgloss.Style
	GitAddStyle     lipgloss.Style
	GitDelStyle     lipgloss.Style
	GitLoadingStyle lipgloss.Style

	// Input styles
	InputPromptStyle lipgloss.Style

	// Help styles
	HelpKeyStyle  lipgloss.Style
	HelpDescStyle lipgloss.Style
	HelpSepStyle  lipgloss.Style

	// Filter style
	FilterStyle lipgloss.Style

	// Border style
	BorderStyle    lipgloss.Style
	SeparatorStyle lipgloss.Style

	// Statusline style
	StatuslineStyle lipgloss.Style

	// Title bar style
	TitleBarStyle lipgloss.Style

	// Prompt style
	PromptStyle lipgloss.Style

	// State line style
	StateStyle lipgloss.Style

	// Table header styles
	TableHeaderStyle     lipgloss.Style
	TableHeaderTextStyle lipgloss.Style

	// CC header label style
	CCHeaderStyle lipgloss.Style

	// Self session styles (pinned current session)
	SelfIndexStyle         lipgloss.Style
	SelfIndexSelectedStyle lipgloss.Style
	SelfNameStyle          lipgloss.Style
	SelfNameSelectedStyle  lipgloss.Style

	// Sidebar button styles
	ButtonStyle        lipgloss.Style
	ButtonKeybindStyle lipgloss.Style
	ButtonWarningStyle lipgloss.Style
	ButtonWarnKbStyle  lipgloss.Style
)

func init() {
	initStyles()
}

// initStyles rebuilds all styles from the current Colors values.
// Called at init and again by InitColors when appearance changes.
func initStyles() {
	AppStyle = lipgloss.NewStyle().
		Border(lipgloss.NormalBorder()).
		BorderForeground(Colors.Fg.Border).
		Padding(0, 1)

	HeaderStyle = lipgloss.NewStyle().
		Bold(true).
		Foreground(Colors.Fg.Accent).
		Padding(0, 1)

	FooterStyle = lipgloss.NewStyle().
		Foreground(Colors.Fg.Subtle).
		Padding(0, 1)

	MessageStyle = lipgloss.NewStyle().
		Foreground(Colors.Fg.Accent).
		Padding(0, 1)

	ErrorMessageStyle = lipgloss.NewStyle().
		Foreground(Colors.Fg.Error).
		Padding(0, 1)

	SessionStyle = lipgloss.NewStyle().
		Padding(0, 1)

	SessionSelectedStyle = lipgloss.NewStyle().
		Padding(0, 1).
		Bold(true).
		Background(Colors.Bg.Selected)

	WindowStyle = lipgloss.NewStyle().
		Padding(0, 1).
		PaddingLeft(10)

	WindowSelectedStyle = lipgloss.NewStyle().
		Padding(0, 1).
		PaddingLeft(10).
		Bold(true).
		Background(Colors.Bg.Selected)

	PaneStyle = lipgloss.NewStyle().
		Padding(0, 1).
		PaddingLeft(14)

	PaneSelectedStyle = lipgloss.NewStyle().
		Padding(0, 1).
		PaddingLeft(14).
		Bold(true).
		Background(Colors.Bg.Selected)

	IndexStyle = lipgloss.NewStyle().
		Foreground(Colors.Fg.Subtle).
		Width(3)

	IndexSelectedStyle = lipgloss.NewStyle().
		Foreground(Colors.Fg.Selected).
		Background(Colors.Bg.Selected).
		Bold(true).
		Width(3)

	SessionNameStyle = lipgloss.NewStyle().
		Foreground(Colors.Fg.SessionName)

	SessionNameSelectedStyle = lipgloss.NewStyle().
		Foreground(Colors.Fg.SessionNameSelected).
		Background(Colors.Bg.Selected).
		Bold(true)

	WindowNameStyle = lipgloss.NewStyle().
		Foreground(Colors.Fg.WindowName)

	WindowNameSelectedStyle = lipgloss.NewStyle().
		Foreground(Colors.Fg.Selected).
		Background(Colors.Bg.Selected).
		Bold(true)

	ExpandedIcon = lipgloss.NewStyle().Foreground(Colors.Fg.Accent).Render("▼")
	ExpandedIconSelected = lipgloss.NewStyle().Foreground(Colors.Fg.Accent).Background(Colors.Bg.Selected).Bold(true).Render("▼")
	CollapsedIcon = lipgloss.NewStyle().Foreground(Colors.Fg.Muted).Render("▶")
	CollapsedIconSelected = lipgloss.NewStyle().Foreground(Colors.Fg.Muted).Background(Colors.Bg.Selected).Bold(true).Render("▶")

	TimeStyle = lipgloss.NewStyle().
		Foreground(Colors.Fg.Muted)

	TimeSelectedStyle = lipgloss.NewStyle().
		Foreground(Colors.Fg.Muted).
		Background(Colors.Bg.Selected).
		Bold(true)

	ClaudeNewStyle = lipgloss.NewStyle().
		Foreground(Colors.Fg.Muted).
		Bold(true)

	ClaudeWorkingStyle = lipgloss.NewStyle().
		Foreground(Colors.Fg.ClaudeWorking).
		Bold(true)

	ClaudeWaitingStyle = lipgloss.NewStyle().
		Foreground(Colors.Fg.ClaudeWaiting).
		Bold(true)

	ClaudeWaitingUrgentStyle = lipgloss.NewStyle().
		Foreground(Colors.Fg.ClaudeUrgent).
		Bold(true)

	ClaudeIdleStyle = lipgloss.NewStyle().
		Foreground(Colors.Fg.ClaudeIdle).
		Bold(true)

	GitFilesStyle = lipgloss.NewStyle().
		Foreground(Colors.Fg.GitFiles)

	GitAddStyle = lipgloss.NewStyle().
		Foreground(Colors.Fg.GitAdd)

	GitDelStyle = lipgloss.NewStyle().
		Foreground(Colors.Fg.GitDel)

	GitLoadingStyle = lipgloss.NewStyle().
		Foreground(Colors.Fg.Muted)

	InputPromptStyle = lipgloss.NewStyle().
		Foreground(Colors.Fg.Accent)

	HelpKeyStyle = lipgloss.NewStyle().
		Foreground(Colors.Fg.Accent).
		Bold(true)

	HelpDescStyle = lipgloss.NewStyle().
		Foreground(Colors.Fg.Muted)

	HelpSepStyle = lipgloss.NewStyle().
		Foreground(Colors.Fg.Muted)

	FilterStyle = lipgloss.NewStyle().
		Foreground(Colors.Fg.Selected).
		Background(Colors.Bg.Selected).
		Bold(true)

	BorderStyle = lipgloss.NewStyle().
		Foreground(Colors.Fg.Border)

	SeparatorStyle = lipgloss.NewStyle().
		Foreground(Colors.Fg.Separator)

	StatuslineStyle = lipgloss.NewStyle().
		Foreground(Colors.Fg.Muted).
		Padding(0, 1)

	TitleBarStyle = lipgloss.NewStyle().
		Background(Colors.Bg.TitleBar).
		Foreground(Colors.Fg.TitleBar).
		Bold(true)

	PromptStyle = lipgloss.NewStyle().
		Foreground(Colors.Fg.Accent).
		Padding(0, 1)

	StateStyle = lipgloss.NewStyle().
		Foreground(Colors.Fg.Muted).
		Padding(0, 1)

	TableHeaderStyle = lipgloss.NewStyle().
		Padding(0, 1)

	TableHeaderTextStyle = lipgloss.NewStyle().
		Bold(true).
		Foreground(Colors.Fg.TableHeader)

	CCHeaderStyle = lipgloss.NewStyle().
		Bold(true).
		Foreground(Colors.Fg.ClaudeHeader)

	SelfIndexStyle = lipgloss.NewStyle().
		Foreground(Colors.Fg.Accent).
		Width(3)

	SelfIndexSelectedStyle = lipgloss.NewStyle().
		Foreground(Colors.Fg.Accent).
		Background(Colors.Bg.Selected).
		Bold(true).
		Width(3)

	SelfNameStyle = lipgloss.NewStyle().
		Foreground(Colors.Fg.Muted)

	SelfNameSelectedStyle = lipgloss.NewStyle().
		Foreground(Colors.Fg.Accent).
		Background(Colors.Bg.Selected).
		Bold(true)

	ButtonStyle = lipgloss.NewStyle().
		Background(Colors.Bg.ButtonAccent).
		Foreground(Colors.Fg.ButtonLabel).
		Bold(true)

	ButtonKeybindStyle = lipgloss.NewStyle().
		Background(Colors.Bg.ButtonAccent).
		Foreground(Colors.Fg.ButtonLabel)

	ButtonWarningStyle = lipgloss.NewStyle().
		Background(Colors.Bg.ButtonWarn).
		Foreground(Colors.Fg.ButtonLabel).
		Bold(true)

	ButtonWarnKbStyle = lipgloss.NewStyle().
		Background(Colors.Bg.ButtonWarn).
		Foreground(Colors.Fg.ButtonLabel)
}

// RenderBorder returns a horizontal border line
func RenderBorder(width int) string {
	return SeparatorStyle.Render(strings.Repeat("─", width))
}

// RenderDottedBorder returns a subtle dotted horizontal line
func RenderDottedBorder(width int) string {
	return SeparatorStyle.Render(strings.Repeat("·", width))
}

// RenderTitleBar renders the inverted title bar with logo on left and view name on right
func RenderTitleBar(logo, viewName string, width int) string {
	// Account for padding in AppStyle (1 on each side)
	innerWidth := width - AppBorderOverheadX
	if innerWidth < 10 {
		innerWidth = 40 // fallback for initial render
	}

	// Calculate spacing between logo and view name
	spacing := innerWidth - len(logo) - len(viewName) - 2 // -2 for padding spaces
	if spacing < 1 {
		spacing = 1
	}

	content := " " + logo + strings.Repeat(" ", spacing) + viewName + " "
	return TitleBarStyle.Width(innerWidth).Render(content)
}

// RenderPrompt renders the prompt line with optional filter text
func RenderPrompt(filter string, width int) string {
	innerWidth := width - AppBorderOverheadX
	if innerWidth < 10 {
		innerWidth = 40 // fallback for initial render
	}
	prompt := "> " + filter
	return PromptStyle.Width(innerWidth).Render(prompt)
}

// RenderFooter renders the 3-line footer (notification, state, hints)
// Deprecated: Use RenderSimpleFooter for new views.
func RenderFooter(notification, state, hints string, isError bool, width int) string {
	innerWidth := width - AppBorderOverheadX
	if innerWidth < 10 {
		innerWidth = 40 // fallback for initial render
	}
	var b strings.Builder

	// Border
	b.WriteString(RenderBorder(innerWidth))
	b.WriteString("\n")

	// Notification line (always 1 line, even if empty)
	if notification != "" {
		if isError {
			b.WriteString(ErrorMessageStyle.Width(innerWidth).Render(notification))
		} else {
			b.WriteString(MessageStyle.Width(innerWidth).Render(notification))
		}
	} else {
		b.WriteString(strings.Repeat(" ", innerWidth))
	}
	b.WriteString("\n")

	// State line (always 1 line, even if empty)
	if state != "" {
		b.WriteString(StateStyle.Width(innerWidth).Render(state))
	} else {
		b.WriteString(strings.Repeat(" ", innerWidth))
	}
	b.WriteString("\n")

	// Hints line
	b.WriteString(FooterStyle.Width(innerWidth).Render(hints))

	return b.String()
}

// RenderSimpleFooter renders a 3-line footer: border + notification + single-line hints.
// Used by views with sidebar (where state/actions are in the sidebar instead).
func RenderSimpleFooter(notification, hints string, isError bool, width int) string {
	innerWidth := width - AppBorderOverheadX
	if innerWidth < 10 {
		innerWidth = 40
	}
	var b strings.Builder

	b.WriteString(RenderBorder(innerWidth))
	b.WriteString("\n")

	if notification != "" {
		if isError {
			b.WriteString(ErrorMessageStyle.Width(innerWidth).Render(notification))
		} else {
			b.WriteString(MessageStyle.Width(innerWidth).Render(notification))
		}
	} else {
		b.WriteString(strings.Repeat(" ", innerWidth))
	}
	b.WriteString("\n")

	b.WriteString(FooterStyle.Width(innerWidth).Render(hints))

	return b.String()
}

// ClaudeSpinnerFrames is the 4-frame braille spinner for "working" state
// Uses bottom 4 dots (positions 2,3,5,6) for better vertical alignment
var ClaudeSpinnerFrames = []string{"⠤", "⠆", "⠒", "⠰"}

// ClaudeWaitThreshold is the duration after which "waiting" escalates from ? to !
const ClaudeWaitThreshold = 5 * time.Minute

// ClaudeIdleThreshold is the duration after which "waiting" escalates from ! to Z
const ClaudeIdleThreshold = 15 * time.Minute

// FormatClaudeIcon formats the Claude status as a single character icon
// animationFrame cycles 0-3 for the spinner, waitDuration determines ? vs !
func FormatClaudeIcon(state string, animationFrame int, waitDuration time.Duration) string {
	switch state {
	case "new":
		// Don't show icon for "new" - it's just noise
		return " "
	case "working":
		// Animated spinner
		frame := animationFrame % len(ClaudeSpinnerFrames)
		return ClaudeWorkingStyle.Render(ClaudeSpinnerFrames[frame])
	case "waiting":
		// Time-based progression: ? → ! → Z
		if waitDuration >= ClaudeIdleThreshold {
			return ClaudeIdleStyle.Render("Z")
		}
		if waitDuration >= ClaudeWaitThreshold {
			return ClaudeWaitingUrgentStyle.Render("!")
		}
		return ClaudeWaitingStyle.Render("?")
	default:
		return " "
	}
}

// GitStatusColumnWidth is the fixed width for the git status column
const GitStatusColumnWidth = 20 // fits "99 files +99 -99"

// FormatGitStatus formats git status for display
// Returns empty string for clean repos (no indicator shown)
// Format: 3 files +44 -7 (files blue, +additions green, -deletions red)
func FormatGitStatus(dirty, additions, deletions int, selected bool) string {
	if dirty == 0 && additions == 0 && deletions == 0 {
		return ""
	}

	// Apply background when selected
	filesStyle := GitFilesStyle
	addStyle := GitAddStyle
	delStyle := GitDelStyle
	if selected {
		filesStyle = filesStyle.Background(Colors.Bg.Selected)
		addStyle = addStyle.Background(Colors.Bg.Selected)
		delStyle = delStyle.Background(Colors.Bg.Selected)
	}

	var parts []string

	if dirty > 0 {
		label := "files"
		if dirty == 1 {
			label = "file"
		}
		parts = append(parts, filesStyle.Render(fmt.Sprintf("%d %s", dirty, label)))
	}
	if additions > 0 {
		parts = append(parts, addStyle.Render(fmt.Sprintf("+%d", additions)))
	}
	if deletions > 0 {
		parts = append(parts, delStyle.Render(fmt.Sprintf("-%d", deletions)))
	}

	if len(parts) == 0 {
		return ""
	}

	// Join with styled spaces when selected
	if selected {
		spacer := lipgloss.NewStyle().Background(Colors.Bg.Selected).Render(" ")
		return strings.Join(parts, spacer)
	}
	return strings.Join(parts, " ")
}

// GitStatusWidth returns the visual width of a git status string (without ANSI codes)
func GitStatusWidth(dirty, additions, deletions int) int {
	if dirty == 0 && additions == 0 && deletions == 0 {
		return 0
	}

	var parts []string

	if dirty > 0 {
		label := "files"
		if dirty == 1 {
			label = "file"
		}
		parts = append(parts, fmt.Sprintf("%d %s", dirty, label))
	}
	if additions > 0 {
		parts = append(parts, fmt.Sprintf("+%d", additions))
	}
	if deletions > 0 {
		parts = append(parts, fmt.Sprintf("-%d", deletions))
	}

	if len(parts) == 0 {
		return 0
	}

	return len(strings.Join(parts, " "))
}

// ScrollbarChars returns scrollbar characters for each visible line
// totalItems: total number of items in the list
// visibleItems: number of items currently visible
// scrollOffset: current scroll position (first visible item index)
// height: number of lines to render scrollbar for
func ScrollbarChars(totalItems, visibleItems, scrollOffset, height int) []string {
	result := make([]string, height)

	// No scrollbar needed if all items fit
	if totalItems <= visibleItems || height <= 0 {
		for i := range result {
			result[i] = " "
		}
		return result
	}

	// Calculate thumb size (minimum 1 line)
	thumbSize := (visibleItems * height) / totalItems
	if thumbSize < 1 {
		thumbSize = 1
	}

	// Calculate thumb position
	scrollRange := totalItems - visibleItems
	trackRange := height - thumbSize
	thumbPos := 0
	if scrollRange > 0 && trackRange > 0 {
		thumbPos = (scrollOffset * trackRange) / scrollRange
	}

	// Build scrollbar using dedicated scrollbar tokens
	trackChar := lipgloss.NewStyle().Foreground(Colors.Fg.ScrollbarTrack).Render("│")
	thumbChar := lipgloss.NewStyle().Foreground(Colors.Fg.ScrollbarThumb).Render("┃")

	for i := 0; i < height; i++ {
		if i >= thumbPos && i < thumbPos+thumbSize {
			result[i] = thumbChar
		} else {
			result[i] = trackChar
		}
	}

	return result
}

package config

import (
	"fmt"
	"os"
	"path/filepath"
	"sort"

	"gopkg.in/yaml.v3"
)

// Appearance represents the terminal color scheme mode
type Appearance string

const (
	AppearanceDark  Appearance = "dark"
	AppearanceLight Appearance = "light"
)

// Config holds all configuration options for helm
type Config struct {
	// Terminal appearance mode ("light" or "dark") - controls color adaptation
	Appearance Appearance `yaml:"appearance"`

	// Layout script name to apply when creating new sessions
	Layout string `yaml:"layout"`

	// Directory containing layout scripts
	LayoutDir string `yaml:"layout_dir"`

	// Enable layout scripts feature (when disabled, layouts won't be auto-applied)
	EnableLayouts bool `yaml:"enable_layouts"`

	// Enable Claude Code status integration
	ClaudeStatusEnabled bool `yaml:"claude_status_enabled"`

	// Enable git status indicator in session list
	GitStatusEnabled bool `yaml:"git_status_enabled"`

	// Directory for status cache files
	CacheDir string `yaml:"cache_dir"`

	// Base directories for project picker (C-p) - supports multiple paths
	ProjectDirs []string `yaml:"project_dirs"`

	// Scan depth for project directories (default: 2 for owner/repo structure)
	ProjectDepth int `yaml:"project_depth"`

	// Default directory for new sessions created with C-n
	DefaultSessionDir string `yaml:"default_session_dir"`

	// Lazygit popup dimensions
	LazygitPopup PopupConfig `yaml:"lazygit_popup"`

	// Quick-access session bookmarks (slots 1-9, maps to M-1 through M-9)
	Bookmarks []Bookmark `yaml:"bookmarks,omitempty"`

	// Command to run on each dirty repo via 'helm repos dirty --walk'
	// Use {} as placeholder for the repo path, e.g. "lazygit -p {}"
	DirtyWalkthroughCommand string `yaml:"dirty_walkthrough_command,omitempty"`

	// Repositories to ensure are cloned (used by helm setup)
	EnsureCloned []EnsureClonedEntry `yaml:"ensure_cloned,omitempty"`
}

// PopupConfig holds popup dimension settings
type PopupConfig struct {
	Width  string `yaml:"width"`
	Height string `yaml:"height"`
}

// Bookmark represents a quick-access session bookmark
type Bookmark struct {
	Path string `yaml:"path"`
}

// EnsureClonedEntry represents a repository to ensure is cloned.
// Supports both string format (just a URL) and object format (url + post_clone).
type EnsureClonedEntry struct {
	URL       string `yaml:"url"`
	PostClone string `yaml:"post_clone,omitempty"`
}

// UnmarshalYAML allows EnsureClonedEntry to be specified as either a plain string or an object.
func (e *EnsureClonedEntry) UnmarshalYAML(value *yaml.Node) error {
	if value.Kind == yaml.ScalarNode {
		e.URL = value.Value
		return nil
	}
	type plain EnsureClonedEntry
	return value.Decode((*plain)(e))
}

// DefaultConfig returns configuration with sensible defaults
func DefaultConfig() Config {
	home := os.Getenv("HOME")
	return Config{
		Appearance:          AppearanceDark,
		Layout:              "",
		LayoutDir:           filepath.Join(home, ".config", "tmux", "layouts"),
		EnableLayouts:       false,
		ClaudeStatusEnabled: false,
		GitStatusEnabled:    false,
		CacheDir:            filepath.Join(home, ".cache", AppDirName),
		ProjectDirs:         []string{filepath.Join(home, "repos")},
		ProjectDepth:        2,
		DefaultSessionDir:   home,
		LazygitPopup: PopupConfig{
			Width:  "90%",
			Height: "90%",
		},
	}
}

// Path returns the path to the config file
func Path() string {
	home := os.Getenv("HOME")
	return filepath.Join(home, ".config", ConfigDirName(), ConfigFileName)
}

// BookmarksPath returns the path to the separate bookmarks file
func BookmarksPath() string {
	home := os.Getenv("HOME")
	return filepath.Join(home, ".config", ConfigDirName(), BookmarksFileName)
}

// BookmarksFile represents the structure of the bookmarks file
type BookmarksFile struct {
	Bookmarks []Bookmark `yaml:"bookmarks"`
}

// Load reads configuration from file and environment variables.
// Priority: env vars > config file > defaults
func Load() (Config, error) {
	cfg := DefaultConfig()

	// Load from config file if it exists
	configPath := Path()
	if _, err := os.Stat(configPath); err == nil {
		data, err := os.ReadFile(configPath)
		if err != nil {
			return cfg, fmt.Errorf("failed to read config file: %w", err)
		}
		if err := yaml.Unmarshal(data, &cfg); err != nil {
			return cfg, fmt.Errorf("failed to parse config file: %w", err)
		}
	}

	// Expand ~ in paths
	cfg.LayoutDir = expandPath(cfg.LayoutDir)
	cfg.CacheDir = expandPath(cfg.CacheDir)
	cfg.DefaultSessionDir = expandPath(cfg.DefaultSessionDir)

	// Expand ~ in project directories
	for i, d := range cfg.ProjectDirs {
		cfg.ProjectDirs[i] = expandPath(d)
	}

	// Expand ~ in bookmark paths
	for i := range cfg.Bookmarks {
		cfg.Bookmarks[i].Path = expandPath(cfg.Bookmarks[i].Path)
	}

	// Ensure ProjectDepth is at least 1
	if cfg.ProjectDepth < 1 {
		cfg.ProjectDepth = 2
	}

	// Environment variables override config file
	if val := os.Getenv("TMUX_LAYOUT"); val != "" {
		cfg.Layout = val
	}
	if val := os.Getenv("TMUX_LAYOUTS_DIR"); val != "" {
		cfg.LayoutDir = expandPath(val)
	}
	if os.Getenv("TMUX_SESSION_PICKER_CLAUDE_STATUS") == "1" {
		cfg.ClaudeStatusEnabled = true
	}
	if os.Getenv("TMUX_SESSION_PICKER_GIT_STATUS") == "1" {
		cfg.GitStatusEnabled = true
	}

	// Load bookmarks from separate file (takes priority over config.yml bookmarks)
	if bookmarks, err := LoadBookmarks(); err == nil {
		cfg.Bookmarks = bookmarks
	}
	// If no separate bookmarks file exists, keep bookmarks from config.yml (for migration)

	return cfg, nil
}

// LoadBookmarks reads bookmarks from the separate bookmarks file
func LoadBookmarks() ([]Bookmark, error) {
	bookmarksPath := BookmarksPath()
	if _, err := os.Stat(bookmarksPath); os.IsNotExist(err) {
		return nil, err
	}

	data, err := os.ReadFile(bookmarksPath)
	if err != nil {
		return nil, fmt.Errorf("failed to read bookmarks file: %w", err)
	}

	var bf BookmarksFile
	if err := yaml.Unmarshal(data, &bf); err != nil {
		return nil, fmt.Errorf("failed to parse bookmarks file: %w", err)
	}

	// Expand ~ in bookmark paths
	for i := range bf.Bookmarks {
		bf.Bookmarks[i].Path = expandPath(bf.Bookmarks[i].Path)
	}

	return bf.Bookmarks, nil
}

// Init creates a new config file with commented defaults
func Init() error {
	configPath := Path()
	configDir := filepath.Dir(configPath)

	// Create directory if needed
	if err := os.MkdirAll(configDir, 0755); err != nil {
		return fmt.Errorf("failed to create config directory: %w", err)
	}

	// Check if file already exists
	if _, err := os.Stat(configPath); err == nil {
		return fmt.Errorf("config file already exists at %s", configPath)
	}

	// Write minimal config — schema descriptions provide documentation
	content := `# yaml-language-server: $schema=https://raw.githubusercontent.com/black-atom-industries/helm/main/schema.json
appearance: dark
project_dirs:
  - ~/repos
`

	if err := os.WriteFile(configPath, []byte(content), 0644); err != nil {
		return fmt.Errorf("failed to write config file: %w", err)
	}

	return nil
}

// SaveBookmarks writes bookmarks to the separate bookmarks file
// This preserves comments in the main config.yml
func (cfg *Config) SaveBookmarks() error {
	bf := BookmarksFile{Bookmarks: cfg.Bookmarks}
	data, err := yaml.Marshal(bf)
	if err != nil {
		return fmt.Errorf("failed to marshal bookmarks: %w", err)
	}

	// Ensure config directory exists
	bookmarksPath := BookmarksPath()
	if err := os.MkdirAll(filepath.Dir(bookmarksPath), 0755); err != nil {
		return fmt.Errorf("failed to create config directory: %w", err)
	}

	if err := os.WriteFile(bookmarksPath, data, 0644); err != nil {
		return fmt.Errorf("failed to write bookmarks file: %w", err)
	}
	return nil
}

// expandPath expands ~ to the user's home directory
func expandPath(path string) string {
	if len(path) > 0 && path[0] == '~' {
		home := os.Getenv("HOME")
		return filepath.Join(home, path[1:])
	}
	return path
}

// RepoInfo represents a cloned repository with its location
type RepoInfo struct {
	Name string // "owner/repo"
	Path string // absolute path on disk
}

// ListClonedRepos returns already-cloned repos in owner/repo format.
// Scans the base path at depth 2 (owner/repo structure).
func ListClonedRepos(basePath string) ([]string, error) {
	var repos []string

	owners, err := os.ReadDir(basePath)
	if err != nil {
		if os.IsNotExist(err) {
			return []string{}, nil
		}
		return nil, err
	}

	for _, owner := range owners {
		if !owner.IsDir() {
			continue
		}

		ownerPath := filepath.Join(basePath, owner.Name())
		repoEntries, err := os.ReadDir(ownerPath)
		if err != nil {
			continue
		}

		for _, repo := range repoEntries {
			if !repo.IsDir() {
				continue
			}

			gitPath := filepath.Join(ownerPath, repo.Name(), ".git")
			if _, err := os.Stat(gitPath); err == nil {
				repos = append(repos, owner.Name()+"/"+repo.Name())
			}
		}
	}

	sort.Strings(repos)
	return repos, nil
}

// FilterUncloned returns repos from available that are not in cloned
func FilterUncloned(available, cloned []string) []string {
	clonedSet := make(map[string]bool)
	for _, r := range cloned {
		clonedSet[r] = true
	}

	var uncloned []string
	for _, r := range available {
		if !clonedSet[r] {
			uncloned = append(uncloned, r)
		}
	}

	return uncloned
}

// ListAllRepos scans all project directories and returns every cloned repo with its path.
// Deduplicates by name — first occurrence wins.
func ListAllRepos(projectDirs []string) ([]RepoInfo, error) {
	seen := make(map[string]bool)
	var all []RepoInfo

	for _, dir := range projectDirs {
		names, err := ListClonedRepos(dir)
		if err != nil {
			continue
		}
		for _, name := range names {
			if seen[name] {
				continue
			}
			seen[name] = true
			all = append(all, RepoInfo{
				Name: name,
				Path: filepath.Join(dir, name),
			})
		}
	}

	return all, nil
}

